// Query Loki for SWARM_TASK and sessions_spawn activity in the last 10 min
const LOKI_URL = 'http://loki:3100';
const WINDOW_MIN = 10;
const END = new Date();
const START = new Date(END.getTime() - WINDOW_MIN * 60 * 1000);

// Query 1: SWARM_TASK tagged messages (structured swarm patterns)
const swarmQuery = '{container="javisi_openclaw"} |~ `SWARM_TASK` !~ `handshake timeout`';
// Query 2: sessions_spawn calls (all agent spawning activity)
const spawnQuery = '{container="javisi_openclaw"} |~ `sessions_spawn|subagent.started|subagent.finished|agent.spawn` !~ `handshake timeout`';

async function queryLoki(query) {
  const url = `${LOKI_URL}/loki/api/v1/query_range?query=${encodeURIComponent(query)}&start=${Math.floor(START.getTime() / 1000)}&end=${Math.floor(END.getTime() / 1000)}&limit=200`;
  const resp = await fetch(url);
  if (!resp.ok) return [];
  const data = await resp.json();
  const results = data?.data?.result || [];
  const lines = [];
  for (const stream of results) {
    for (const [ts, line] of (stream.values || [])) {
      lines.push({
        timestamp: new Date(parseInt(ts.slice(0, 13))).toISOString(),
        line: line.slice(0, 500)
      });
    }
  }
  return lines;
}

const [swarmLines, spawnLines] = await Promise.all([
  queryLoki(swarmQuery),
  queryLoki(spawnQuery)
]);

// Parse swarm patterns from tagged messages
const swarmTasks = {};
for (const entry of swarmLines) {
  const match = entry.line.match(/SWARM_TASK\s+(fan-out|pipeline|broadcast|loop):([\w-]+)/);
  if (match) {
    const [, pattern, id] = match;
    if (!swarmTasks[id]) swarmTasks[id] = { pattern, id, count: 0, firstSeen: entry.timestamp, lastSeen: entry.timestamp };
    swarmTasks[id].count++;
    swarmTasks[id].lastSeen = entry.timestamp;
  }
}

// Count agent spawn activity by agent name
const agentActivity = {};
for (const entry of spawnLines) {
  // Try to extract agent IDs from spawn logs
  const agentMatch = entry.line.match(/(?:agentId|agent)["':\s]+([a-z_-]+)/i);
  if (agentMatch) {
    const agent = agentMatch[1];
    agentActivity[agent] = (agentActivity[agent] || 0) + 1;
  }
}

return [{ json: {
  window_minutes: WINDOW_MIN,
  timestamp: END.toISOString(),
  swarm_tasks: Object.values(swarmTasks),
  swarm_task_count: Object.keys(swarmTasks).length,
  spawn_events: spawnLines.length,
  agent_activity: agentActivity,
  total_swarm_lines: swarmLines.length,
  total_spawn_lines: spawnLines.length
}}];

// Detect anomalies in swarm activity
const data = $input.first().json;
const alerts = [];

// Check for stuck swarm tasks (same task seen >20 times in 10min = possible loop)
for (const task of (data.swarm_tasks || [])) {
  if (task.count > 20) {
    alerts.push({
      severity: 'critical',
      type: 'swarm_loop',
      message: `Swarm task ${task.pattern}:${task.id} has ${task.count} events in ${data.window_minutes}min — possible infinite loop`,
      task
    });
  } else if (task.count > 10) {
    alerts.push({
      severity: 'warning',
      type: 'swarm_high_activity',
      message: `Swarm task ${task.pattern}:${task.id} has ${task.count} events in ${data.window_minutes}min — high activity`,
      task
    });
  }
}

// Check for excessive spawn events (>30 in 10min = token burn risk)
if (data.spawn_events > 30) {
  alerts.push({
    severity: 'warning',
    type: 'excessive_spawns',
    message: `${data.spawn_events} agent spawn events in ${data.window_minutes}min — high token consumption risk`
  });
}

// Check for single agent domination (>60% of all spawns)
const totalSpawns = Object.values(data.agent_activity || {}).reduce((a, b) => a + b, 0);
for (const [agent, count] of Object.entries(data.agent_activity || {})) {
  if (totalSpawns > 5 && count / totalSpawns > 0.6) {
    alerts.push({
      severity: 'info',
      type: 'agent_domination',
      message: `Agent '${agent}' accounts for ${Math.round(count/totalSpawns*100)}% of spawn activity (${count}/${totalSpawns})`
    });
  }
}

const hasAlerts = alerts.some(a => a.severity === 'critical' || a.severity === 'warning');

// Update staticData with latest stats for status endpoint
const $static = $getWorkflowStaticData('global');
$static.lastCheck = data.timestamp;
$static.lastStats = {
  swarm_tasks: data.swarm_task_count,
  spawn_events: data.spawn_events,
  agent_activity: data.agent_activity,
  alerts_count: alerts.length
};

return [{ json: { ...data, alerts, hasAlerts, alert_count: alerts.length } }];

// Format Telegram alert for swarm anomalies
// HTML-escape untrusted log content to prevent injection in Telegram HTML messages
function esc(s) { return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

const data = $input.first().json;
const alerts = data.alerts || [];
const critical = alerts.filter(a => a.severity === 'critical');
const warnings = alerts.filter(a => a.severity === 'warning');

let msg = '';
if (critical.length > 0) {
  msg += '🚨 <b>SWARM CRITICAL</b>\n';
  for (const a of critical) msg += `• ${esc(a.message)}\n`;
}
if (warnings.length > 0) {
  msg += '⚠️ <b>Swarm Warnings</b>\n';
  for (const a of warnings) msg += `• ${esc(a.message)}\n`;
}

msg += `\n📊 <b>Stats ${data.window_minutes}min</b>: ${data.swarm_task_count} swarm tasks, ${data.spawn_events} spawn events`;

// Top agents
const sorted = Object.entries(data.agent_activity || {}).sort((a, b) => b[1] - a[1]).slice(0, 5);
if (sorted.length > 0) {
  msg += '\n🤖 Top agents: ' + sorted.map(([a, c]) => `${esc(a)}(${c})`).join(', ');
}

return [{ json: { message: msg } }];

// Return swarm status for webhook endpoint
const $static = $getWorkflowStaticData('global');
const stats = $static.lastStats || {};
return [{ json: {
  status: 'ok',
  lastCheck: $static.lastCheck || null,
  swarm_tasks: stats.swarm_tasks || 0,
  spawn_events: stats.spawn_events || 0,
  agent_activity: stats.agent_activity || {},
  alerts_count: stats.alerts_count || 0
}}];
